import React, { useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

function StockDetails() {
  const [symbol, setSymbol] = useState("");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");

  const handleFetch = async () => {
    setError("");
    setData(null);

    try {
      const res = await axios.get(`/api/stock/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data.");
    }
  };

  const renderCharts = () => {
    if (!data || !data.dailyPrices) return null;

    const dates = Object.keys(data.dailyPrices).reverse();
    const closes = dates.map(
      (date) => parseFloat(data.dailyPrices[date]["4. close"])
    );

    const smaDates = Object.keys(data.sma || {}).reverse();
    const smaValues = smaDates.map(
      (date) => parseFloat(data.sma[date]["SMA"])
    );

    const earnings = data.earnings || [];
    const earningsYears = earnings.map(e => e.fiscalDateEnding);
    const earningsEPS = earnings.map(e => parseFloat(e.reportedEPS));

    const peRatio = parseFloat(data.overview?.PERatio) || 0;
    const dividendYield = parseFloat(data.overview?.DividendYield) || 0;
    const marketCap = data.overview?.MarketCapitalization || "-";
    const weekHigh = data.overview?.["52WeekHigh"] || "-";
    const weekLow = data.overview?.["52WeekLow"] || "-";
    const profitMargin = data.overview?.ProfitMargin || "-";
    const roe = data.overview?.ReturnOnEquityTTM || "-";
    const debtEquity = data.overview?.DebtToEquity || "-";

    return (
      <div>
        {/* Daily Close Price Chart */}
        <h4>Daily Close Price</h4>
        <Line
          data={{
            labels: dates,
            datasets: [
              {
                label: `${symbol} Close Price`,
                data: closes,
                borderColor: "blue",
                fill: false,
              },
            ],
          }}
          height={100}
        />

        {/* SMA Chart */}
        {smaDates.length > 0 && (
          <>
            <h4>10-Day SMA</h4>
            <Line
              data={{
                labels: smaDates,
                datasets: [
                  {
                    label: "SMA",
                    data: smaValues,
                    borderColor: "green",
                    fill: false,
                  },
                ],
              }}
              height={100}
            />
          </>
        )}

        {/* EPS Bar Chart */}
        {earnings.length > 0 && (
          <>
            <h4>Annual Earnings (EPS)</h4>
            <Bar
              data={{
                labels: earningsYears,
                datasets: [
                  {
                    label: "Reported EPS",
                    data: earningsEPS,
                    backgroundColor: "orange",
                  },
                ],
              }}
              height={100}
            />
          </>
        )}

        {/* PE Ratio Pie */}
        <h4>Fundamentals</h4>
        <ul>
          <li>Market Cap: {marketCap}</li>
          <li>PE Ratio: {peRatio}</li>
          <li>Dividend Yield: {dividendYield}</li>
          <li>52-Week High: {weekHigh}</li>
          <li>52-Week Low: {weekLow}</li>
          <li>Profit Margin: {profitMargin}</li>
          <li>Return on Equity (ROE): {roe}</li>
          <li>Debt to Equity: {debtEquity}</li>
        </ul>
      </div>
    );
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>US Stock Details (Alpha Vantage)</h2>
      <input
        type="text"
        placeholder="Enter symbol (e.g. AAPL)"
        value={symbol}
        onChange={(e) => setSymbol(e.target.value)}
      />
      <button onClick={handleFetch}>Fetch</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <div style={{ marginTop: "20px" }}>
          <h3>{data.overview?.Name} ({data.overview?.Symbol})</h3>
          <p>{data.overview?.Description}</p>

          <ul>
            <li>Sector: {data.overview?.Sector}</li>
            <li>Industry: {data.overview?.Industry}</li>
          </ul>

          {renderCharts()}
        </div>
      )}
    </div>
  );
}

export default StockDetails;
